CREATE OR REPLACE FUNCTION gos_share_buymonth (as_memno char,ai_year integer,ai_month integer) RETURNS bigint AS $body$
DECLARE

  ldt_date_fr timestamp(0);
  ldt_date_to timestamp(0);
  ldc_share_month bigint;

BEGIN
  ldt_date_fr := to_date('1/'||trim(both ai_month)||'/'||trim(both ai_year) ,'dd/mm/yyyy');
  ldt_date_to := pka_srv_datetime.fp_lastdayofmonth(ldt_date_fr);

  select sum( coalesce(sd.share_value,0)*su.sign_flag )
  into STRICT ldc_share_month
  from sc_mem_m_share_holding_detail sd , sc_mem_m_ucf_share_item_type su
  where ( sd.operate_date between ldt_date_fr and ldt_date_to )
  and sd.item_type = su.item_type
  and sd.membership_no = as_memno;

  return coalesce(ldc_share_month,0);
exception when others then RAISE EXCEPTION '%', 'gos_share_buymonth>'||trim(both sqlerrm) USING ERRCODE = '45000';
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
